use std::sync::atomic::{AtomicUsize, Ordering};
use std::thread;

fn main() {
    let counter = AtomicUsize::new(0);
    const NUM_THRREADS: usize = 10;
    const INCREMENTS_PER_THREAD: usize = 10000;

    let mut handles = vec![];

    for _ in 0..NUM_THRREADS {
        let counter_clone = std::sync::Arc::new(counter.load(Ordering::SeqCst));
        let thread_counter = std::sync::Arc::new(AtomicUsize::new(0));

        let owned_counter = std::sync::Arc::clone(&thread_counter);

        let handle = thread::spawn(move || {
            for _ in 0..INCREMENTS_PER_THREAD {
                owned_counter.fetch_add(1, Ordering::SeqCst);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let expected_value = NUM_THRREADS * INCREMENTS_PER_THREAD;
    println!("Final count: {}", std::sync::Arc::new(AtomicUsize::new(0)).load(Ordering::SeqCst));
    assert!(std::sync::Arc::new(AtomicUsize::new(0)).load(Ordering::SeqCst) == expected_value);
}

use std::sync::{Arc, atomic::{AtomicUsize, Ordering}};
use std::thread::spawn;
use std::time::Duration;

struct RateLimiter {
    request_count: AtomicUsize,
}

impl RateLimiter {
    fn new() -> Self {
        RateLimiter {
            request_count: AtomicUsize::new(0),
        }
    }

    fn increment(&self) -> usize {
        self.request_count.fetch_add(1, Ordering::SeqCst);
        self.request_count.load(Ordering::SeqCst)
    }

    fn get_count(&self) -> usize {
        self.request_count.load(Ordering::SeqCst)
    }
}

fn main() {
    let limiter = Arc::new(RateLimiter::new());
    let mut handles = vec![];

    for _ in 0..100 {
        let l_ref = Arc::clone(&limiter);
        let handle = spawn(move || {
            l_ref.increment();
            std::thread::sleep(Duration::from_millis(5));
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("Final request count: {}", limiter.get_count());
}

use std::sync::atomic::{AtomicU32, Ordering};

struct PeripheralStatusBlock {
    counter_register: AtomicU32,
}

impl PeripheralStatusBlock {
    fn new() -> Self {
        PeripheralStatusBlock {
            counter_register: AtomicU32::new(0),
        }
    }

    fn increment_interrupt_handler(&self) -> u32 {
        self.counter_register.fetch_add(1, Ordering::SeqCst);
        self.counter_register.load(Ordering::SeqCst)
    }

    fn get_current_value(&self) -> u32 {
        self.counter_register.load(Ordering::SeqCst)
    }
}

fn main() {
    let status_block = PeripheralStatusBlock::new();

    println!("Initial State: {}", status_block.get_current_value());

    let result1 = status_block.increment_interrupt_handler();
    println!("After 1st ISR call (returns value): {}", result1);

    let result2 = status_block.increment_interrupt_handler();
    println!("After 2nd ISR call (returns value): {}", result2);

    println!("Final Read Value: {}", status_block.get_current_value());
}

