use std::sync::atomic::{AtomicUsize, Ordering};
use std::thread;

fn main() {
    let counter = AtomicUsize::new(0);
    let num_threads = 10;
    let iterations_per_thread = 10000;
    let mut handles = vec![];

    for _ in 0..num_threads {
        let local_counter = counter.load(Ordering::SeqCst);
        let handle = thread::spawn(move || {
            let local_counter_ref = AtomicUsize::new(local_counter);
            for _ in 0..iterations_per_thread {
                local_counter_ref.fetch_add(1, Ordering::SeqCst);
            }
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    let final_count = counter.load(Ordering::SeqCst);
    println!("Total count reached: {}", final_count);
}
